using Contoso.Scoring;

namespace Contoso.Scoring.Tests;

[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calculator = new();

    // ── CalculatePercentage ──────────────────────────────────────

    [TestMethod]
    [DataRow(7, 10, 70.0)]
    [DataRow(10, 10, 100.0)]
    [DataRow(0, 5, 0.0)]
    [DataRow(1, 3, 33.333333333333336)]
    public void CalculatePercentage_ValidInputs_ReturnsExpected(int correct, int total, double expected)
    {
        var result = _calculator.CalculatePercentage(correct, total);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void CalculatePercentage_ResultIsInValidRange()
    {
        var result = _calculator.CalculatePercentage(8, 10);

        // Assert.IsInRange verifies the value falls within [low, high]
        Assert.IsInRange(result, 0.0, 100.0);
    }

    [TestMethod]
    public void CalculatePercentage_PerfectScore_IsGreaterThanOrEqualTo100()
    {
        var result = _calculator.CalculatePercentage(10, 10);

        // Assert.IsGreaterThan / IsLessThan for boundary checks
        Assert.IsGreaterThan(99.9, result);
        Assert.AreEqual(100.0, result);
    }

    [TestMethod]
    public void CalculatePercentage_PartialScore_IsLessThanPerfect()
    {
        var result = _calculator.CalculatePercentage(9, 10);

        Assert.IsLessThan(100.0, result);
        Assert.IsGreaterThan(0.0, result);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(11, 10));
    }

    // ── GetGrade ─────────────────────────────────────────────────

    [TestMethod]
    [DataRow(100.0, "A")]
    [DataRow(90.0, "A")]
    [DataRow(89.9, "B")]
    [DataRow(80.0, "B")]
    [DataRow(79.9, "C")]
    [DataRow(70.0, "C")]
    [DataRow(69.9, "D")]
    [DataRow(60.0, "D")]
    [DataRow(59.9, "F")]
    [DataRow(0.0, "F")]
    public void GetGrade_AtBoundaries_ReturnsCorrectGrade(double percentage, string expected)
    {
        var grade = _calculator.GetGrade(percentage);

        Assert.AreEqual(expected, grade);
    }

    [TestMethod]
    public void GetGrade_NegativePercentage_ReturnsF()
    {
        var grade = _calculator.GetGrade(-5.0);

        Assert.AreEqual("F", grade);
    }

    // ── NormalizeScore ───────────────────────────────────────────

    [TestMethod]
    [DataRow(50.0, 100.0, 50.0)]
    [DataRow(25.0, 50.0, 50.0)]
    [DataRow(0.0, 100.0, 0.0)]
    [DataRow(100.0, 100.0, 100.0)]
    public void NormalizeScore_ValidInputs_ReturnsExpected(double raw, double max, double expected)
    {
        var result = _calculator.NormalizeScore(raw, max);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void NormalizeScore_Result_IsAlwaysInRange()
    {
        // Even with a raw score exceeding the max, output is capped at 100
        var result = _calculator.NormalizeScore(150.0, 100.0);

        Assert.IsInRange(result, 0.0, 100.0);
        Assert.AreEqual(100.0, result);
    }

    [TestMethod]
    public void NormalizeScore_PartialRaw_IsGreaterThanZero()
    {
        var result = _calculator.NormalizeScore(30.0, 100.0);

        Assert.IsGreaterThan(0.0, result);
        Assert.IsLessThan(100.0, result);
    }

    [TestMethod]
    public void NormalizeScore_ExceedingMax_CapsAt100()
    {
        var result = _calculator.NormalizeScore(200.0, 100.0);

        // Verify the cap: result should not exceed 100
        Assert.IsLessThan(100.1, result);
        Assert.AreEqual(100.0, result);
    }

    [TestMethod]
    public void NormalizeScore_NegativeRaw_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(-1.0, 100.0));
    }

    [TestMethod]
    public void NormalizeScore_ZeroMax_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(50.0, 0.0));
    }
}

